import { useContext, useMemo } from "react";
import { GET_TODAY_OPTION } from "../../dateRange/dateRangeUtils";
import { userFormatContext } from "../userFormat/userFormatContext";
import { normalizeDates } from "../../filtersBar/components/filtersBarPeriodPicker/normalizeDates";
export const useTodayButton = (dateRangeMode, disableFutureDates, disablePastDates, disableDatesBefore, disableDatesAfter) => {
    const { toLocalDateTime, toReverseOffsetDateTime } = useContext(userFormatContext);
    const today = GET_TODAY_OPTION(toLocalDateTime, (s) => s, toReverseOffsetDateTime).getRange();
    const normalizedDates = normalizeDates(today.from.toISOString(), today.to.toISOString(), disableFutureDates, disablePastDates, disableDatesBefore, disableDatesAfter);
    const isTodayDisabled = useMemo(() => dateRangeMode
        ? today.from.toISOString() !== normalizedDates.from && today.to.toISOString() !== normalizedDates.to
        : !(new Date(normalizedDates.from).getTime() >= today.from.getTime() &&
            new Date(normalizedDates.from).getTime() <= today.to.getTime()), [dateRangeMode, normalizedDates.from, normalizedDates.to, today.from, today.to]);
    return { isTodayDisabled, todayFrom: normalizedDates.from, todayTo: normalizedDates.to };
};
