export const getPillTypeClassName = (type) => {
    switch (type) {
        case "info":
            return "zen-pill-type--info";
        case "success":
            return "zen-pill-type--success";
        case "warning":
            return "zen-pill-type--warning";
        case "error":
            return "zen-pill-type--error";
        case "default":
        case undefined:
        default:
            return "zen-pill-type--default";
    }
};
