import { isFilterState } from "../groupsFilterRaw/groupsHelper";
export const getCurrentSelectionFromIds = (items, comboArr) => items.map((item) => {
    const currentItem = comboArr.find((comboItem) => comboItem.id === item.id);
    return currentItem
        ? { id: currentItem.id, name: currentItem.name, color: currentItem.color }
        : { id: item.id, name: item.id, color: undefined };
});
export const isFilterStateLeafItem = (state) => {
    // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    const items = state.items || [];
    return !items.length || !items.some(isFilterState);
};
