const createColumnSettings = (c) => ({
    name: c.id,
    visible: c.visible || true,
    width: (c.meta || {}).defaultWidth
});
const findPrevColumnIndex = (columns, settings, index) => {
    if (index === 0) {
        return 0;
    }
    const name = columns[index - 1].id;
    return settings.findIndex(s => s.name === name) + 1;
};
export const mergeColumnsSettings = (columns, savedSettings) => {
    const columnSettingsMap = new Set(savedSettings.map(s => s.name));
    let settings = savedSettings;
    if (settings.length === 0) {
        return columns.map(createColumnSettings);
    }
    // we should add all new columns that we don't have in settings
    for (let i = 0; i < columns.length; ++i) {
        const column = columns[i];
        if (!columnSettingsMap.has(column.id)) {
            const index = findPrevColumnIndex(columns, settings, i);
            settings = [...settings.slice(0, index), createColumnSettings(column), ...settings.slice(index)];
        }
    }
    return settings;
};
