import { useCallback } from "react";
import { FOCUSABLE_SELECTOR } from "../../utils/focusableSelector";
import { isChildOf } from "../../utils/isChildOf";
import { useKeydown } from "./useKeydown";
export const useArrowKey = (containerRef, callback, subscriptionTrigger, condition) => {
    const handleKeyDown = useCallback((e) => {
        if (e.key === "ArrowLeft") {
            const target = e.target;
            if (!target || !containerRef.current) {
                return;
            }
            const isPopupFocused = isChildOf(target, containerRef.current);
            const focusable = containerRef.current.querySelectorAll(FOCUSABLE_SELECTOR);
            const isParentMenu = !!target.closest("[role='menu']");
            const role = target.getAttribute("role") || "";
            const isMenuItemRole = ["menuitem", "menuitemcheckbox", "menuitemradio"].includes(role);
            if ((isPopupFocused || !focusable.length) && isParentMenu && isMenuItemRole) {
                callback();
                return;
            }
        }
    }, [callback, containerRef]);
    useKeydown(handleKeyDown, subscriptionTrigger, condition);
};
