import { Children } from "react";
export const getComponentText = (comp) => {
    const buffer = [];
    if (comp) {
        if (typeof comp === "string" || typeof comp === "number") {
            buffer.push(comp.toString());
        }
        else if (typeof comp === "object") {
            const children = comp.props.children;
            buffer.push(...Children.toArray(children).map(child => getComponentText(child)));
        }
    }
    return buffer.join(" ");
};
export const isFunction = (obj) => typeof obj === "function";
