import { FilterMenuStep } from "../groupsFilterInterfaces";
import { UiStateActionType } from "./uiStateActionType";
export const uiInitialGroupsFilterState = {
    isOpen: false,
    hasError: false,
    isLoading: false,
    step: FilterMenuStep.Initial,
    currentAdjustmentId: undefined,
    uncheckedAdjustmentIds: [],
    uncheckedAdvancedState: undefined,
    searchValue: "",
    isOpenAdvancedFilter: false
};
export function uiStateReducer(state, action) {
    const { type, payload } = action;
    switch (type) {
        case UiStateActionType.SetIsOpen:
            return Object.assign(Object.assign({}, state), { isOpen: payload });
        case UiStateActionType.SetAdvancedFilterIsOpen:
            return Object.assign(Object.assign({}, state), { isOpenAdvancedFilter: payload });
        case UiStateActionType.ToggleOpen:
            return state.isOpenAdvancedFilter ? state : Object.assign(Object.assign({}, state), { isOpen: !state.isOpen });
        case UiStateActionType.SetLoadWithError:
            return Object.assign(Object.assign({}, state), { hasError: payload.hasError, isLoading: payload.isLoading });
        case UiStateActionType.SetStep:
            return Object.assign(Object.assign({}, state), { step: payload });
        case UiStateActionType.SetCurrentAdjustmentId:
            return Object.assign(Object.assign({}, state), { currentAdjustmentId: payload });
        case UiStateActionType.SetUncheckedAdjustmentIds:
            return Object.assign(Object.assign({}, state), { uncheckedAdjustmentIds: [...payload] });
        case UiStateActionType.SetUncheckedAdvancedState:
            return Object.assign(Object.assign({}, state), { uncheckedAdvancedState: payload });
        case UiStateActionType.ClearUncheckedState:
            return Object.assign(Object.assign({}, state), { uncheckedAdvancedState: undefined, uncheckedAdjustmentIds: [] });
        case UiStateActionType.SetSearchValue:
            return Object.assign(Object.assign({}, state), { searchValue: payload });
        default: {
            throw Error("Unknown action: " + type);
        }
    }
}
