export const getActionablePillStateClassName = (disabled = false, readonly = false, active = false) => {
    if (disabled) {
        return "zen-pill-actionable--disabled";
    }
    if (readonly) {
        return "zen-pill-actionable--readonly";
    }
    if (active) {
        return "zen-pill-actionable--active";
    }
    return "zen-pill-actionable--default";
};
